class Solution {
public:
    Node* construct(vector<vector<int>>& g) {
        function<Node*(int,int,int)> build=[&](int r,int c,int s)->Node*{
            int v=g[r][c];
            for(int i=r;i<r+s;i++) for(int j=c;j<c+s;j++) if(g[i][j]!=v)
                return new Node(true,false,
                    build(r,c,s/2), build(r,c+s/2,s/2),
                    build(r+s/2,c,s/2), build(r+s/2,c+s/2,s/2));
            return new Node(v==1,true);
        };
        return build(0,0,g.size());
    }
};
